// This kernel performs the cross-section lookup for a specific material type,
// after the materials and energies have been sorted.
__kernel void xs_lookup_kernel_optimization_6(Inputs in, __global SimulationData *GSD_ptr, int m, int n_lookups, int offset )
{
	// Get the local and group IDs to calculate the global work-item ID.
	int i = get_group_id(0) * get_local_size(0) + get_local_id(0);

	// If the work-item ID is out of bounds for the number of lookups in this material, return.
	if( i >= n_lookups )
		return;

	// Adjust the index by the offset to get the correct global lookup index.
	i += offset;

	// Access the global SimulationData structure.
	__global SimulationData GSD = *GSD_ptr;

	// Get the material type for the current lookup.
	int mat = GSD.mat_samples[i];
	// If the material type does not match the kernel's target material, return.
	if( mat != m )
		return;

	// Array to store the macroscopic cross-section results.
	double macro_xs_vector[5] = {0};

	// Perform the macroscopic cross-section lookup.
	calculate_macro_xs(
			GSD.p_energy_samples[i],        // Sampled neutron energy (in lethargy)
			mat,             // Sampled material type index neutron is in
			in.n_isotopes,   // Total number of isotopes in simulation
