			GSD.num_nucs,     // 1-D array with number of nuclides per material
			GSD.concs,        // Flattened 2-D array with concentration of each nuclide in each material
			GSD.unionized_energy_array, // 1-D Unionized energy array
			GSD.index_grid,   // Flattened 2-D grid holding indices into nuclide grid for each unionized energy level
			GSD.nuclide_grid, // Flattened 2-D grid holding energy levels and XS_data for all nuclides in simulation
			GSD.mats,         // Flattened 2-D array with nuclide indices defining composition of each type of material
			macro_xs_vector, // 1-D array with result of the macroscopic cross section (5 different reaction channels)
			in.grid_type,    // Lookup type (nuclide, hash, or unionized)
			in.hash_bins,    // Number of hash bins used (if using hash lookup type)
			GSD.max_num_nucs  // Maximum number of nuclides present in any material
			);

	// For verification purposes, find the maximum value in the macro_xs_vector
	// and use its index to update the verification value.
	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++ )
	{
		if( macro_xs_vector[j] > max )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}
	// Store the verification result for this lookup.
	GSD.verification[i] = max_idx+1;
}

// Calculates the microscopic cross section for a given nuclide and energy.
// This function interpolates between grid points to find the cross section.
__device__ void calculate_micro_xs( double p_energy, int nuc, long n_isotopes,
                           long n_gridpoints,
                           __global double * __restrict__ egrid, __global int * __restrict__ index_data,
                           __global NuclideGridPoint * __restrict__ nuclide_grids,
                           long idx, double * __restrict__ xs_vector, int grid_type, int hash_bins ){
	// Variables for interpolation
	double f;
	__global NuclideGridPoint * low, * high;

	// Determine the indices for the lower and upper bounding grid points based on the grid type.
	if( grid_type == NUCLIDE )
	{
		// If using the nuclide grid directly, perform a binary search to find the energy index.
		idx = grid_search_nuclide( n_gridpoints, p_energy, &nuclide_grids[nuc*n_gridpoints], 0, n_gridpoints-1);

		// Get the pointer to the lower bounding grid point. Handle edge case for the last grid point.
		if( idx == n_gridpoints - 1 )
			low = &nuclide_grids[nuc*n_gridpoints + idx - 1];
		else
			low = &nuclide_grids[nuc*n_gridpoints + idx];
	}
	else if( grid_type == UNIONIZED) // Unionized Energy Grid
	{
		// If using the unionized energy grid, the index is already known.
		// Get the pointer to the lower bounding grid point. Handle edge case.
		if( index_data[idx * n_isotopes + nuc] == n_gridpoints - 1 )
			low = &nuclide_grids[nuc*n_gridpoints + index_data[idx * n_isotopes + nuc] - 1];
		else
			low = &nuclide_grids[nuc*n_gridpoints + index_data[idx * n_isotopes + nuc]];
	}
	else // Hash grid
	{
		// For the hash grid, determine the lower and upper bounding indices.
		int u_low = index_data[idx * n_isotopes + nuc];
		int u_high;
		if( idx == hash_bins - 1 )
			u_high = n_gridpoints - 1;
		else
			u_high = index_data[(idx+1)*n_isotopes + nuc] + 1;

		// Perform a binary search within the determined bounds to find the precise grid point.
		double e_low  = nuclide_grids[nuc*n_gridpoints + u_low].energy;
		double e_high = nuclide_grids[nuc*n_gridpoints + u_high].energy;
		int lower;
		if( p_energy <= e_low )
			lower = 0;
		else if( p_energy >= e_high )
			lower = n_gridpoints - 1;
		else
			lower = grid_search_nuclide( n_gridpoints, p_energy, &nuclide_grids[nuc*n_gridpoints], u_low, u_high);

		// Get the pointer to the lower bounding grid point. Handle edge case.
		if( lower == n_gridpoints - 1 )
			low = &nuclide_grids[nuc*n_gridpoints + lower - 1];
		else
			low = &nuclide_grids[nuc*n_gridpoints + lower];
	}

	// The upper bounding grid point is the next one after the lower.
	high = low + 1;

	// Calculate the interpolation factor 'f'.
	f = (high->energy - p_energy) / (high->energy - low->energy);

	// Linearly interpolate the cross sections between the lower and upper grid points.
	xs_vector[0] = high->total_xs - f * (high->total_xs - low->total_xs); // Total XS
	xs_vector[1] = high->elastic_xs - f * (high->elastic_xs - low->elastic_xs); // Elastic XS
	xs_vector[2] = high->absorbtion_xs - f * (high->absorbtion_xs - low->absorbtion_xs); // Absorption XS
	xs_vector[3] = high->fission_xs - f * (high->fission_xs - low->fission_xs); // Fission XS
	xs_vector[4] = high->nu_fission_xs - f * (high->nu_fission_xs - low->nu_fission_xs); // Nu Fission XS
}

// Calculates the macroscopic cross section for a given material and energy.
// This involves summing the contributions of each nuclide in the material.
__device__ void calculate_macro_xs( double p_energy, int mat, long n_isotopes,
                         long n_gridpoints, __global int * __restrict__ num_nucs,
                         __global double * __restrict__ concs,
                         __global double * __restrict__ egrid, __global int * __restrict__ index_data,
                         __global NuclideGridPoint * __restrict__ nuclide_grids,
                         __global int * __restrict__ mats,
                         double * __restrict__ macro_xs_vector, int grid_type, int hash_bins, int max_num_nucs ){
	int p_nuc; // The nuclide index we are looking up.
	long idx = -1;	// The index in the energy grid.
	double conc; // The concentration of the nuclide in the material.

	// Initialize the macroscopic cross-section vector to zero.
	for( int k = 0; k < 5; k++ )
		macro_xs_vector[k] = 0;

	// Determine the energy grid index based on the grid type.
	if( grid_type == UNIONIZED )
		idx = grid_search( n_isotopes * n_gridpoints, p_energy, egrid);	
	else if( grid_type == HASH )
	{
		double du = 1.0 / hash_bins;
		idx = p_energy / du;
	}

	// Iterate through each nuclide in the material.
	for( int j = 0; j < num_nucs[mat]; j++ )
	{
		double xs_vector[5]; // Microscopic cross sections for the current nuclide.
		p_nuc = mats[mat*max_num_nucs + j]; // Get the nuclide index.
		conc = concs[mat*max_num_nucs + j]; // Get the nuclide concentration.

		// Calculate the microscopic cross sections for the current nuclide.
		calculate_micro_xs( p_energy, p_nuc, n_isotopes,
		                    n_gridpoints, egrid, index_data,
		                    nuclide_grids, idx, xs_vector, grid_type, hash_bins );

		// Add the contribution of this nuclide to the macroscopic cross section.
		// (micro_xs * concentration)
		for( int k = 0; k < 5; k++ )
			macro_xs_vector[k] += xs_vector[k] * conc;
	}
}


// Binary search for the energy index in the unionized energy grid.
// Returns the lower index of the energy bin containing the queried energy.
__device__ long grid_search( long n, double quarry, __global double * __restrict__ A)
{
	long lowerLimit = 0;
	long upperLimit = n-1;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	// Standard binary search loop.
	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );

		if( A[examinationPoint] > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;

		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

// Binary search for the energy index in a nuclide's energy grid.
// Returns the lower index of the energy bin containing the queried energy.
__device__ long grid_search_nuclide( long n, double quarry, __global NuclideGridPoint * A, long low, long high)
{
	long lowerLimit = low;
	long upperLimit = high;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	// Standard binary search loop.
	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );

		if( A[examinationPoint].energy > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;

		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

// Picks a material based on a probabilistic distribution.
// The distribution is hardcoded based on typical material fractions in a reactor core.
__device__ int pick_mat( uint64_t * seed )
{
	// Material distribution probabilities (by volume).
	double dist[12];
	dist[0]  = 0.140;	// fuel
	dist[1]  = 0.052;	// cladding
	dist[2]  = 0.275;	// cold, borated water
	dist[3]  = 0.134;	// hot, borated water
	dist[4]  = 0.154;	// RPV
	dist[5]  = 0.064;	// Lower, radial reflector
	dist[6]  = 0.066;	// Upper reflector / top plate
	dist[7]  = 0.055;	// bottom plate
	dist[8]  = 0.008;	// bottom nozzle
	dist[9]  = 0.015;	// top nozzle
	dist[10] = 0.025;	// top of fuel assemblies
	dist[11] = 0.013;	// bottom of fuel assemblies

	// Generate a random number to pick a material.
	double roll = LCG_random_double(seed);

	// Determine which material was picked based on the distribution.
	for( int i = 0; i < 12; i++ )
	{
		double running = 0;
		for( int j = i; j > 0; j-- )
			running += dist[j];
		if( roll < running )
			return i;
	}

	// Default to material 0 if something goes wrong.
	return 0;
}

// Generates a random double between 0.0 and 1.0 using a Linear Congruential Generator (LCG).
__device__ double LCG_random_double(uint64_t * seed)
{
	// LCG parameters (modulus m = 2^63, multiplier a, increment c).
	const uint64_t m = 9223372036854775808ULL; // 2^63
	const uint64_t a = 2806196910506780709ULL;
	const uint64_t c = 1ULL;
	// Update the seed using the LCG formula.
	*seed = (a * (*seed) + c) % m;
	// Return the random number as a double between 0.0 and 1.0.
	return (double) (*seed) / (double) m;
}	

// Fast-forwards the LCG state by 'n' steps.
// This is useful for generating independent sequences of random numbers.
__device__ uint64_t fast_forward_LCG(uint64_t seed, uint64_t n)
{
	// LCG parameters.
	const uint64_t m = 9223372036854775808ULL; // 2^63
	uint64_t a = 2806196910506780709ULL;
	uint64_t c = 1ULL;

	// Ensure n is within the modulus range.
	n = n % m;

	// Variables for matrix exponentiation (used for fast-forwarding).
	uint64_t a_new = 1;
	uint64_t c_new = 0;

	// Perform matrix exponentiation to calculate the state after 'n' steps.
	while(n > 0) 
	{
		if(n & 1) // If the current bit of n is 1
		{
			a_new *= a; // Update multiplier
			c_new = c_new * a + c; // Update increment
		}
		// Square the multiplier and increment for the next bit.
		c *= (a + 1);
		a *= a;

		n >>= 1; // Move to the next bit of n.
	}

	// Return the new seed after fast-forwarding.
	return (a_new * seed + c_new) % m;
}

// This kernel performs the sampling of random energies and materials.
// It is called before the cross-section lookup kernel.
__kernel void sampling_kernel(Inputs in, __global SimulationData *GSD_ptr )
{
	// Get the global ID of the work-item. This corresponds to the lookup index.
	const int i = get_group_id(0) * get_local_size(0) + get_local_id(0);

	// If the index is out of bounds, return.
	if( i >= in.lookups )
		return;

	// Set the initial seed value for the random number generator.
	uint64_t seed = STARTING_SEED;	

	// Forward the seed to the current lookup index. We need two samples per lookup
	// (energy and material), so we advance the seed by 2*i.
	seed = fast_forward_LCG(seed, 2*i);

	// Randomly pick an energy and material for the particle.
	double p_energy = LCG_random_double(&seed);
	int mat         = pick_mat(&seed); 

	// Access the global SimulationData structure.
	__global SimulationData GSD = *GSD_ptr;

	// Store the sampled energy and material in the device memory.
	GSD.p_energy_samples[i] = p_energy;
	GSD.mat_samples[i] = mat;
}

